// Blob mascot — organic SDF smooth-blend showcase, voxel engine.
// Face is on the -Y side (front). Z is up. ~45mm tall.
const { voxels, sdf } = api;
const v = voxels();

// ---- Body: a fat lower egg smoothly blended into a slightly narrower head
//      bump on top → a chunky teardrop. Built so the bottom dips below z=0,
//      then sliced flat with a half-space.
const body = sdf.ellipsoid(15, 14, 13).translate(0, 0, 15);   // chunky lower body
const head = sdf.ellipsoid(12, 11, 9).translate(0, 0, 27);    // head bump on top
let blob = body.smoothUnion(head, 6);

// ---- Feet: two stubby ellipsoids that protrude below the body front, blended
//      in. They sit lower than the body center so their front+bottom voxels are
//      "deepest inside" the foot region → they take the darker-green color.
const footL = sdf.ellipsoid(8, 9, 6).translate(-9, -3, 3).label('foot');
const footR = sdf.ellipsoid(8, 9, 6).translate(9, -3, 3).label('foot');
blob = blob.smoothUnion(footL, 4).smoothUnion(footR, 4);

// ---- Arms: little side nubs that stick out past the body (darker green).
const armL = sdf.ellipsoid(6, 5, 7).translate(-17, 0, 18).label('foot');
const armR = sdf.ellipsoid(6, 5, 7).translate(17, 0, 18).label('foot');
blob = blob.smoothUnion(armL, 4).smoothUnion(armR, 4);

// ---- Flatten the bottom: intersect with a half-space whose lower face is z=0.
const halfSpace = sdf.box([200, 200, 200]).translate(0, 0, 100);
blob = blob.intersect(halfSpace);

// Rasterize the green body. res 0.75 keeps it ~45mm tall and chunky.
const RES = 0.75;
v.sdf(blob, {
  res: RES,
  color: '#7ed957',              // mint-green body
  colors: { foot: '#4caf50' },   // darker-green feet + arms
});

// ---- FACE on the -Y side, painted as decals onto the front surface.
// frontDecal walks +Y..-Y down to the first occupied voxel at (x,z) and recolors
// it (and optionally a few layers in) so the feature wraps the curved front.
function frontDecal(x, z, c, depth = 1) {
  let painted = 0;
  // find frontmost (most -Y) occupied voxel at this column
  for (let y = -40; y <= 40; y++) {
    if (v.has(x, y, z)) {
      for (let d = 0; d < depth && v.has(x, y + d, z); d++) v.set(x, y + d, z, c);
      return true;
    }
  }
  return false;
}
function disc(cx, cz, r, c, depth = 1) {
  for (let x = cx - r; x <= cx + r; x++)
    for (let z = cz - r; z <= cz + r; z++)
      if ((x - cx) ** 2 + (z - cz) ** 2 <= r * r) frontDecal(x, z, c, depth);
}

// Face geometry in VOXEL coords (world / RES). Head center ~ (0, ., 30) world
// → z ≈ 40 in voxels. Eyes a bit below the head crown, mouth below the eyes.
const EYE_Z = 34, EYE_X = 8, MOUTH_Z = 27;

// White eye whites
disc(-EYE_X, EYE_Z, 4, '#ffffff', 2);
disc(EYE_X, EYE_Z, 4, '#ffffff', 2);
// Dark pupils, slightly lower-inner
disc(-EYE_X + 1, EYE_Z - 1, 2, '#222222', 2);
disc(EYE_X - 1, EYE_Z - 1, 2, '#222222', 2);

// Pink cheeks, below + outside the eyes
disc(-EYE_X - 5, EYE_Z - 5, 2, '#ff9eb5', 1);
disc(EYE_X + 5, EYE_Z - 5, 2, '#ff9eb5', 1);

// Smile: a shallow upward arc of dark voxels (z = MOUTH_Z + bend up at ends).
for (let x = -6; x <= 6; x++) {
  const z = MOUTH_Z + Math.round((x * x) / 12); // parabola opening up → smile
  frontDecal(x, z, '#222222', 2);
  frontDecal(x, z - 1, '#222222', 2);
}

// ---- Recolor feet + arms darker green. The smoothUnion blends them into the
// body, so the SDF "deepest-inside" rule keeps them body-colored; instead we
// recolor every occupied voxel inside each ellipsoidal foot/arm zone (voxel
// coords; bottom is z=0). This makes the darker-green feet/arms read clearly in
// the silhouette without changing geometry.
const FOOT = '#4caf50';
function recolorZone(cx, cy, cz, rx, ry, rz, c) {
  for (let x = Math.floor(cx - rx); x <= Math.ceil(cx + rx); x++)
    for (let y = Math.floor(cy - ry); y <= Math.ceil(cy + ry); y++)
      for (let z = Math.floor(cz - rz); z <= Math.ceil(cz + rz); z++) {
        const e = ((x - cx) / rx) ** 2 + ((y - cy) / ry) ** 2 + ((z - cz) / rz) ** 2;
        if (e <= 1 && v.has(x, y, z)) v.set(x, y, z, c);
      }
}
// Feet: two rounded darker-green foot pads at the bottom front, with a gap
// between them so they read as two distinct feet (not a skirt).
function footPad(cx, cz, rx, rz) {
  for (let x = cx - rx; x <= cx + rx; x++)
    for (let z = Math.max(0, cz - rz); z <= cz + rz; z++) {
      const e = ((x - cx) / rx) ** 2 + ((z - cz) / rz) ** 2;
      if (e <= 1.05) frontDecal(x, z, FOOT, 4);
    }
}
footPad(-11, 4, 8, 5);
footPad(11, 4, 8, 5);
// Arms (world ±17,0,18 → voxels ±23,0,24): recolor the outer front of each nub.
recolorZone(-23, -4, 24, 8, 8, 10, FOOT);
recolorZone(23, -4, 24, 8, 8, 10, FOOT);

return v;
